previewCss:
.darma-loader-cssloaders-github-32 {
  display: inline-block;
  width: 104px;
  height: 12px;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #ec4899) 16%, transparent);
  overflow: hidden;
}
.darma-loader-cssloaders-github-32::before {
      content: "";
      display: block;
      width: 42%;
      height: 100%;
      border-radius: inherit;
      background: linear-gradient(90deg, var(--loader-color, #ec4899), var(--loader-secondary-color, #fbcfe8));
      animation: darma-loader-cssloaders-github-32-progressSlide 0.9s ease-in-out infinite;
    }
    @keyframes darma-loader-cssloaders-github-32-progressSlide { 0% { transform: translateX(-120%); } 100% { transform: translateX(260%); } }

